// LCD clock + stats - drives the ST7735 display from a script.
//
// Wire the display to the C5 (3.3V logic):
//   VIN->3V3  GND->GND  SCK->GPIO6  MOSI->GPIO7
//   TFT_CS->GPIO8  D/C->GPIO9  RESET->GPIO10
// The SIMULATOR renders the screen right on the component - no wiring
// needed to develop; flash + wire to see it for real.

fn on_start() {
    lcd_init(6, 7, 8, 9, 10);        // sck, mosi, cs, dc, rst
    lcd_clear(0, 0, 40);             // deep blue
    lcd_text(10, 6, "WIRELAB", 255, 220, 80);
    lcd_rect(6, 20, 116, 2, 255, 220, 80);
    this.last = 0;
    log("lcd running");
}

fn on_tick(dt_ms) {
    let t = millis() / 1000;
    if t == this.last { return; }
    this.last = t;
    // Repaint just the changing region, not the whole screen.
    lcd_rect(10, 40, 108, 14, 0, 0, 40);
    lcd_text(10, 42, `uptime ${t}s`, 220, 220, 220);
    lcd_rect(10, 60, 108, 14, 0, 0, 40);
    let beat = if t % 2 == 0 { "tick" } else { "tock" };
    lcd_text(10, 62, beat, 90, 220, 120);
}
